+				inBlock = true
+				continue
+			}
+			if matches := singleImport.FindStringSubmatch(line); len(matches) > 1 {
+				seen[matches[1]] = struct{}{}
+			}
+			continue
+		}
+		if strings.HasPrefix(line, ")") {
+			inBlock = false
+			continue
